 10→func TestLoad(t *testing.T) {
 11→	dir := t.TempDir()
 12→	yaml := `repo_url: git@github.com:org/repo.git
 13→project_path: /home/user/project/myrepo
 14→default_branch: main
 15→extra_ro_mounts:
 16→  - /home/user/.cargo
 17→  - /home/user/.rustup
 18→extra_rw_mounts:
 19→  - /tmp/scratch
 20→agent_env:
 21→  DATABASE_URL: "postgres://localhost:5432/dev"
 22→  FOO: bar
 23→`
 24→	if err := os.WriteFile(filepath.Join(dir, "workspace.yaml"), []byte(yaml), 0644); err != nil {
 25→		t.Fatal(err)
 26→	}
 27→
 28→	ws, err := Load(dir)
 29→	if err != nil {
 30→		t.Fatalf("Load() error: %v", err)
 31→	}
 32→
 33→	tests := []struct {
 34→		name string
 35→		got  string
 36→		want string
 37→	}{
 38→		{"RepoURL", ws.Config.RepoURL, "git@github.com:org/repo.git"},
 39→		{"ProjectPath", ws.Config.ProjectPath, "/home/user/project/myrepo"},
 40→		{"DefaultBranch", ws.Config.DefaultBranch, "main"},
 41→	}
 42→	for _, tt := range tests {
 43→		t.Run(tt.name, func(t *testing.T) {
 44→			if tt.got != tt.want {
 45→				t.Errorf("got %q, want %q", tt.got, tt.want)
 46→			}
 47→		})
 48→	}
 49→
 50→	if len(ws.Config.ExtraROMounts) != 2 {
 51→		t.Errorf("ExtraROMounts: got %d items, want 2", len(ws.Config.ExtraROMounts))
 52→	}
 53→	if len(ws.Config.ExtraRWMounts) != 1 {
 54→		t.Errorf("ExtraRWMounts: got %d items, want 1", len(ws.Config.ExtraRWMounts))
 55→	}
 56→	if ws.Config.AgentEnv["DATABASE_URL"] != "postgres://localhost:5432/dev" {
 57→		t.Errorf("AgentEnv[DATABASE_URL] = %q", ws.Config.AgentEnv["DATABASE_URL"])
 58→	}
 59→	if ws.Config.AgentEnv["FOO"] != "bar" {
 60→		t.Errorf("AgentEnv[FOO] = %q", ws.Config.AgentEnv["FOO"])
 61→	}
 62→}
